#include <iostream>
#include <vector>
#include <map>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <cstring>
#include <arpa/inet.h>

struct Player {
    int id;
    float x, y, z;
    float rotation;
    int health;
};

struct Packet {
    int type;
    int player_id;
    float x, y, z;
    float rotation;
    int action;
};

class GameServer {
private:
    int socket_fd;
    sockaddr_in server_addr;
    std::map<int, Player> players;
    std::vector<Packet> packet_queue;
    int next_player_id;

public:
    GameServer() : next_player_id(1) {
        socket_fd = socket(AF_INET, SOCK_DGRAM, 0);
        memset(&server_addr, 0, sizeof(server_addr));
        server_addr.sin_family = AF_INET;
        server_addr.sin_addr.s_addr = INADDR_ANY;
        server_addr.sin_port = htons(8080);
        bind(socket_fd, (struct sockaddr*)&server_addr, sizeof(server_addr));
    }

    void process_packets() {
        char buffer[1024];
        socklen_t addr_len = sizeof(server_addr);
        int bytes_received = recvfrom(socket_fd, buffer, sizeof(buffer), 0,
                                      (struct sockaddr*)&server_addr, &addr_len);

        if (bytes_received > 0) {
            Packet packet;
            memcpy(&packet, buffer, sizeof(Packet));
            packet_queue.push_back(packet);
        }

        for (const auto& packet : packet_queue) {
            if (packet.type == 0) { // Position update
                if (players.find(packet.player_id) == players.end()) {
                    players[packet.player_id] = {packet.player_id, packet.x, packet.y, packet.z, packet.rotation, 100};
                } else {
                    players[packet.player_id].x = packet.x;
                    players[packet.player_id].y = packet.y;
                    players[packet.player_id].z = packet.z;
                    players[packet.player_id].rotation = packet.rotation;
                }
            } else if (packet.type == 1) { // Shooting
                if (players.find(packet.player_id) != players.end()) {
                    // Simple hit detection - just reduce health of nearby players
                    for (auto& pair : players) {
                        Player& target = pair.second;
                        if (target.id != packet.player_id) {
                            float distance = sqrt(pow(target.x - players[packet.player_id].x, 2) +
                                                 pow(target.y - players[packet.player_id].y, 2) +
                                                 pow(target.z - players[packet.player_id].z, 2));
                            if (distance < 10.0f) {
                                target.health -= 25;
                                if (target.health <= 0) {
                                    target.health = 0;
                                }
                            }
                        }
                    }
                }
            }
        }
        packet_queue.clear();
    }

    void send_updates() {
        for (const auto& pair : players) {
            const Player& player = pair.second;
            char buffer[sizeof(Player)];
            memcpy(buffer, &player, sizeof(Player));
            sendto(socket_fd, buffer, sizeof(Player), 0,
                   (struct sockaddr*)&server_addr, sizeof(server_addr));
        }
    }

    void run() {
        while (true) {
            process_packets();
            send_updates();
            usleep(10000); // 10ms delay
        }
    }
};

int main() {
    GameServer server;
    server.run();
    return 0;
}